# type: ignore

import os

import numpy as np
from lxml import etree


class BoundingImage:
    names = {"x": 0, "y": 1, "z": 2}

    def __init__(
        self, point_min, point_max, k, axis_width=0, axis_height=1, axis_depth=2
    ):
        self._set_axes((axis_width, axis_height, axis_depth))
        self.k = k
        self.min = tuple(point_min)
        self.max = tuple(point_max)
        self.set_projection_plane(axis_width, axis_height, axis_depth)

    def _set_axes(self, axes):
        self.axes = tuple(axis for axis in axes)
        self.axisWidth, self.axisHeight, self.axisDepth = axes

    def _set_max_voxel(self):
        self.maxVoxel = self.get_voxel_coordinates(self.max)

    def _set_image_shape(self):
        """Refreshes the image dimensions"""
        self.shape = tuple(map(lambda x: x + 1, self.maxVoxel))
        self.width, self.height, self.depth = self.shape

    def set_projection_plane(self, axis_width, axis_height, axis_depth):
        """Defines the projection plane, where each parameter can accept three values:
        0 for the x axis, 1 for the y axis and 2 for the z axis
        """
        self._set_axes((axis_width, axis_height, axis_depth))
        self._set_max_voxel()
        self._set_image_shape()

    def get_float_coordinates(self, point):
        """Get the float coordinates of a point in the voxel grid"""
        return tuple(
            (point[axis] - self.min[axis]) / self.k for _, axis in zip(point, self.axes)
        )

    def get_voxel_coordinates(self, point):
        """Get the coordinates of a point in the voxel grid"""
        return tuple(int(coord) for coord in self.get_float_coordinates(point))

    def get_coordinates(self, point):
        """Get the coordinates of a point in the pixel grid"""
        return self.get_voxel_coordinates(point)[:2]

    def get_point(self, voxel):
        """Get the coordinates of a voxel in the global coordinates system"""
        return tuple(
            voxel[axis] * self.k + self.min[axis] for _, axis in zip(voxel, self.axes)
        )

    def write_point_in_node(self, node, point):
        for name, i in self.names.items():
            subelement = etree.SubElement(node, name)
            subelement.text = str(point[i])

    @classmethod
    def get_identifier_from_name(cls, name):
        return cls.names[name]

    @classmethod
    def parse_point_in_node(cls, node):
        point = np.zeros(len(node))
        for child in node:
            point[cls.get_identifier_from_name(child.tag)] = float(child.text)
        return point

    def save_config(self, path):
        xml_path = BoundingImage.get_config_path(path)
        bounding_image = etree.Element("bounding_image")
        tree = etree.ElementTree(bounding_image)
        self.write_point_in_node(etree.SubElement(bounding_image, "min"), self.min)
        self.write_point_in_node(etree.SubElement(bounding_image, "max"), self.max)
        k_node = etree.SubElement(bounding_image, "k")
        k_node.text = str(self.k)
        with open(xml_path, "wb") as file_object:
            tree.write(file_object)

    @classmethod
    def open(cls, path):
        tree = etree.parse(path)
        minimum = cls.parse_point_in_node(tree.find("min"))
        maximum = cls.parse_point_in_node(tree.find("max"))
        k = float(tree.find("k").text)
        return cls(minimum, maximum, k)

    @classmethod
    def get_config_path(cls, path):
        return os.path.splitext(path)[0] + ".xml"

    def __add__(self, other):
        if list(self.axes) != list(other.axes):
            raise ValueError(
                "BoundingImages should have the same projection axis to be summed"
            )
        bounding_image = BoundingImage(
            np.minimum(self.min, other.min),
            np.maximum(self.max, other.max),
            min(self.k, other.k),
        )
        bounding_image.set_projection_plane(
            self.axisWidth, self.axisHeight, self.axisDepth
        )
        return bounding_image

    def __radd__(self, other):
        return self if other == 0 else self.__add__(other)
